class CookieConsent{constructor(){this.cookieName="magix_consent",this.cookieDurationDays=365,this.checkboxes=document.querySelectorAll(".cookie-checkbox"),this.initEvents()}initEvents(){const e=document.getElementById("btnAcceptAll"),t=document.getElementById("btnRefuseAll"),c=document.getElementById("btnAcceptModal"),o=document.getElementById("btnRefuseModal"),n=document.getElementById("btnSaveSelection");e&&e.addEventListener("click",(()=>this.acceptAll())),c&&c.addEventListener("click",(()=>this.acceptAll())),t&&t.addEventListener("click",(()=>this.refuseAll())),o&&o.addEventListener("click",(()=>this.refuseAll())),n&&n.addEventListener("click",(()=>this.saveSelection()))}acceptAll(){this.checkboxes.forEach((e=>e.checked=!0)),this.saveSelection()}refuseAll(){this.checkboxes.forEach((e=>e.checked=!1)),this.saveSelection()}saveSelection(){const e={};this.checkboxes.forEach((t=>{e[t.name]=t.checked})),this.setCookie(this.cookieName,JSON.stringify(e),this.cookieDurationDays);const t=document.getElementById("cookiesModal");if(t){const e=bootstrap.Modal.getInstance(t);e&&e.hide()}window.location.reload()}setCookie(e,t,c){let o="";if(c){const e=new Date;e.setTime(e.getTime()+24*c*60*60*1e3),o="; expires="+e.toUTCString()}document.cookie=e+"="+(t||"")+o+"; path=/; SameSite=Lax"}}document.addEventListener("DOMContentLoaded",(()=>{new CookieConsent}));